import{_ as a,o as t,c as r,a0 as n}from"./chunks/framework.jwovEGr5.js";const u=JSON.parse('{"title":"Glossary","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/glossary.md","filePath":"getting-started/glossary.md"}'),o={name:"getting-started/glossary.md"};function i(s,e,l,h,c,d){return t(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="glossary" tabindex="-1">Glossary <a class="header-anchor" href="#glossary" aria-label="Permalink to &quot;Glossary&quot;">​</a></h1><p>Every term the rest of the documentation relies on, defined in plain language. When a guide uses one of these words for the first time, it links back here. Terms are grouped, but you can also just search the page.</p><hr><h2 id="structure-people" tabindex="-1">Structure &amp; people <a class="header-anchor" href="#structure-people" aria-label="Permalink to &quot;Structure &amp; people&quot;">​</a></h2><h3 id="kingdom" tabindex="-1">Kingdom <a class="header-anchor" href="#kingdom" aria-label="Permalink to &quot;Kingdom&quot;">​</a></h3><p>The top‑level group in the app, matching an in‑game kingdom/server. A kingdom contains alliances, players, events, and its own settings. Run by a <strong>King</strong>.</p><h3 id="alliance" tabindex="-1">Alliance <a class="header-anchor" href="#alliance" aria-label="Permalink to &quot;Alliance&quot;">​</a></h3><p>A group of players inside a kingdom. Run by an <strong>Alliance Leader</strong> (with help from <strong>Co‑Leaders</strong>). Most day‑to‑day tracking happens at the alliance level.</p><h3 id="player" tabindex="-1">Player <a class="header-anchor" href="#player" aria-label="Permalink to &quot;Player&quot;">​</a></h3><p>A single governor tracked in the app. A player belongs to an alliance and carries details like power, alliance rank, status, and a <a href="#nickname-history">nickname history</a>.</p><h3 id="nickname-history" tabindex="-1">Nickname history <a class="header-anchor" href="#nickname-history" aria-label="Permalink to &quot;Nickname history&quot;">​</a></h3><p>The record of the names a player has used over time. Because governors rename themselves, the app keeps past nicknames so it can still recognize a player on new screenshots and keep their results connected.</p><h3 id="role" tabindex="-1">Role <a class="header-anchor" href="#role" aria-label="Permalink to &quot;Role&quot;">​</a></h3><p>The label on your account that decides what you can see and do. The five built‑in roles are <strong>Supreme Admin</strong>, <strong>King</strong>, <strong>Alliance Leader</strong>, <strong>Co‑Leader</strong>, and <strong>Alliance Player</strong>. See <a href="./../roles/overview.html">Roles Explained</a>.</p><h3 id="assignment" tabindex="-1">Assignment <a class="header-anchor" href="#assignment" aria-label="Permalink to &quot;Assignment&quot;">​</a></h3><p>The link between a user and a role <em>at a particular place</em>. For example, &quot;Alliance Leader of [ABC] alliance&quot; is one assignment. A single person can have several assignments (see <a href="#multiple-roles">multiple roles</a>).</p><h3 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h3><p>How far your access reaches: <strong>global</strong> (whole platform), <strong>kingdom</strong> (one kingdom), or <strong>alliance</strong> (one alliance). Your role&#39;s scope is why you can see some data but not other kingdoms&#39; or alliances&#39; data.</p><h3 id="context-context-banner" tabindex="-1">Context (context banner) <a class="header-anchor" href="#context-context-banner" aria-label="Permalink to &quot;Context (context banner)&quot;">​</a></h3><p>The strip near the top of the screen that shows which kingdom and alliance you are currently working inside, plus your role. It tells you <em>where</em> your actions will apply. See <a href="./navigating.html">Finding Your Way Around</a>.</p><h3 id="multiple-roles" tabindex="-1">Multiple roles <a class="header-anchor" href="#multiple-roles" aria-label="Permalink to &quot;Multiple roles&quot;">​</a></h3><p>Some people hold more than one role (for example, a King who is also a Co‑Leader somewhere). The app combines all of their assignments, and a stronger role is <strong>never weakened</strong> by also holding a lesser one. Covered in the roles section.</p><hr><h2 id="events-scoring" tabindex="-1">Events &amp; scoring <a class="header-anchor" href="#events-scoring" aria-label="Permalink to &quot;Events &amp; scoring&quot;">​</a></h2><h3 id="event-template" tabindex="-1">Event template <a class="header-anchor" href="#event-template" aria-label="Permalink to &quot;Event template&quot;">​</a></h3><p>A reusable <em>definition</em> of an event — its name, rules, scoring style, and stages. A template is the recipe. The app ships with several <strong>default templates</strong> (Bear Trap, Alliance Brawl, and others). You can edit templates, and you can create your own. Default templates can be edited but <strong>not deleted</strong> — see <a href="./../roles/protection-rules.html">Safety Rules</a>.</p><h3 id="event-instance" tabindex="-1">Event instance <a class="header-anchor" href="#event-instance" aria-label="Permalink to &quot;Event instance&quot;">​</a></h3><p>One <em>actual occurrence</em> of an event on real dates — for example, &quot;Bear Trap — March 3.&quot; Scores are recorded against an instance, not against the template. Also called a <strong>session</strong> in a few places.</p><h3 id="stage" tabindex="-1">Stage <a class="header-anchor" href="#stage" aria-label="Permalink to &quot;Stage&quot;">​</a></h3><p>A sub‑round inside an event that has multiple parts (for example, each day of a multi‑day brawl). Some events have stages; many don&#39;t.</p><h3 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h3><p>One player&#39;s score and/or participation in one event instance. Results are the numbers everything else (analytics, rewards) is built from.</p><h3 id="participation" tabindex="-1">Participation <a class="header-anchor" href="#participation" aria-label="Permalink to &quot;Participation&quot;">​</a></h3><p>Whether a player took part in an event, separate from any score. Some events are scored by points; others only track who showed up.</p><h3 id="snapshot" tabindex="-1">Snapshot <a class="header-anchor" href="#snapshot" aria-label="Permalink to &quot;Snapshot&quot;">​</a></h3><p>A saved picture of who was in an alliance at a certain moment — used to decide who counts as a participant in an event instance. Because members join and leave, the app can &quot;freeze&quot; the roster at the start of an instance so scoring stays fair.</p><h3 id="reward-eligibility" tabindex="-1">Reward eligibility <a class="header-anchor" href="#reward-eligibility" aria-label="Permalink to &quot;Reward eligibility&quot;">​</a></h3><p>The app&#39;s calculation of which players earned a reward, based on <strong>reward rules</strong> you define. It flags eligible players so a leader can hand out prizes and mark them as handled.</p><hr><h2 id="imports-data-entry" tabindex="-1">Imports &amp; data entry <a class="header-anchor" href="#imports-data-entry" aria-label="Permalink to &quot;Imports &amp; data entry&quot;">​</a></h2><h3 id="import" tabindex="-1">Import <a class="header-anchor" href="#import" aria-label="Permalink to &quot;Import&quot;">​</a></h3><p>An upload of screenshots (or a spreadsheet) that the app reads to pull out player names and scores. An import is always a <strong>draft first</strong>: it stages the data for you to check and changes nothing about your real players or results until you accept it.</p><h3 id="review-row" tabindex="-1">Review row <a class="header-anchor" href="#review-row" aria-label="Permalink to &quot;Review row&quot;">​</a></h3><p>One line inside an import — usually one player and their score — waiting for you to check it. Each review row has a status (for example, <em>ready</em>, <em>needs review</em>, <em>conflict</em>, <em>ignored</em>, <em>accepted</em>). You edit, accept, or ignore rows during review. Accepting a row is the moment its data is actually saved.</p><h3 id="accept-apply" tabindex="-1">Accept / apply <a class="header-anchor" href="#accept-apply" aria-label="Permalink to &quot;Accept / apply&quot;">​</a></h3><p>The action that turns a reviewed row into a real, saved result (and, for player imports, updates the player). Before you accept, nothing is written.</p><h3 id="manual-entry" tabindex="-1">Manual entry <a class="header-anchor" href="#manual-entry" aria-label="Permalink to &quot;Manual entry&quot;">​</a></h3><p>Typing scores in yourself instead of uploading screenshots. Ends in the same place as an import: saved results on an event instance.</p><h3 id="ocr-image-reading" tabindex="-1">OCR (image reading) <a class="header-anchor" href="#ocr-image-reading" aria-label="Permalink to &quot;OCR (image reading)&quot;">​</a></h3><p>The technology that reads text and numbers out of your screenshots. The app offers a <strong>free local</strong> reader and a <strong>premium (Gemini)</strong> reader that you power with your own key. You don&#39;t need to know how it works — just which one you picked.</p><hr><h2 id="deleting-recovering" tabindex="-1">Deleting &amp; recovering <a class="header-anchor" href="#deleting-recovering" aria-label="Permalink to &quot;Deleting &amp; recovering&quot;">​</a></h2><h3 id="soft-delete" tabindex="-1">Soft delete <a class="header-anchor" href="#soft-delete" aria-label="Permalink to &quot;Soft delete&quot;">​</a></h3><p>&quot;Deleting&quot; most things (players, events, imports, alliances, kingdoms) doesn&#39;t erase them — it moves them to the <strong>Recycle Bin</strong>, where they can be restored. See <a href="./../reference/soft-delete.html">What &quot;Delete&quot; Really Does</a>.</p><h3 id="recycle-bin" tabindex="-1">Recycle Bin <a class="header-anchor" href="#recycle-bin" aria-label="Permalink to &quot;Recycle Bin&quot;">​</a></h3><p>The place where soft‑deleted items wait. People with the right permission can <strong>restore</strong> an item, or <strong>purge</strong> it (permanently remove it). Purging cannot be undone.</p><h3 id="purge" tabindex="-1">Purge <a class="header-anchor" href="#purge" aria-label="Permalink to &quot;Purge&quot;">​</a></h3><p>Permanently removing a soft‑deleted item from the Recycle Bin. This is the one action that truly destroys data, so it&#39;s limited to senior roles.</p><h3 id="rollback" tabindex="-1">Rollback <a class="header-anchor" href="#rollback" aria-label="Permalink to &quot;Rollback&quot;">​</a></h3><p>Undoing an import that was already applied — the app removes the results that import created, putting things back the way they were. Covered in the imports section.</p><hr><h2 id="subscriptions-premium" tabindex="-1">Subscriptions &amp; premium <a class="header-anchor" href="#subscriptions-premium" aria-label="Permalink to &quot;Subscriptions &amp; premium&quot;">​</a></h2><blockquote><p>These terms were checked against the current app. A couple of common assumptions are <strong>wrong</strong>, so read carefully.</p></blockquote><h3 id="plan" tabindex="-1">Plan <a class="header-anchor" href="#plan" aria-label="Permalink to &quot;Plan&quot;">​</a></h3><p>A subscription tier that sets what a kingdom or alliance can do and how much it can store. There are free plans and premium plans, for kingdoms and for alliances.</p><h3 id="free-tier-fallback-plan" tabindex="-1">Free tier (fallback plan) <a class="header-anchor" href="#free-tier-fallback-plan" aria-label="Permalink to &quot;Free tier (fallback plan)&quot;">​</a></h3><p>Every kingdom and alliance always has <em>at least</em> a free plan, even if nobody assigned one. This fallback works quietly in the background — you may never see it named, but it&#39;s why limits still apply to brand‑new alliances.</p><h3 id="effective-plan" tabindex="-1">Effective plan <a class="header-anchor" href="#effective-plan" aria-label="Permalink to &quot;Effective plan&quot;">​</a></h3><p>The plan that <strong>actually applies to you right now</strong>. The app works it out from strongest to weakest source:</p><ol><li><strong>Direct alliance plan</strong> — the alliance has its own subscription.</li><li><strong>Accepted kingdom grant</strong> — a King offered their kingdom&#39;s plan to the alliance and the alliance accepted (see <a href="#grant">grant</a>).</li><li><strong>Direct kingdom plan</strong> — for a kingdom itself, its own subscription.</li><li><strong>Free tier</strong> — if none of the above apply.</li></ol><p><strong>Important:</strong> an alliance does <strong>not</strong> automatically inherit its kingdom&#39;s plan just because the kingdom has one. The King must <em>grant</em> the plan and the alliance must <em>accept</em> it. Without that, the alliance stays on its own plan (or the free tier).</p><h3 id="grant" tabindex="-1">Grant <a class="header-anchor" href="#grant" aria-label="Permalink to &quot;Grant&quot;">​</a></h3><p>When a King offers their kingdom&#39;s premium plan to a specific alliance. The alliance&#39;s leader must <strong>accept</strong> the offer before it takes effect, and either side can later revoke it. How many alliances a King can grant to is <strong>set by the kingdom&#39;s plan</strong> (the free kingdom plan allows none; a premium kingdom plan allows several) — it is not a fixed universal number.</p><h3 id="allocation" tabindex="-1">Allocation <a class="header-anchor" href="#allocation" aria-label="Permalink to &quot;Allocation&quot;">​</a></h3><p>When a King divides up the kingdom plan&#39;s limits among the alliances they&#39;ve granted to — for example, giving each granted alliance a share of the player limit. The shares can&#39;t add up to more than the kingdom&#39;s own limit.</p><h3 id="quota-limit" tabindex="-1">Quota / limit <a class="header-anchor" href="#quota-limit" aria-label="Permalink to &quot;Quota / limit&quot;">​</a></h3><p>The maximum amount of something (players, events, screenshots, storage, and so on) your plan allows. As you approach a limit you&#39;ll see warnings; passing it can block creating more.</p><h3 id="suspension" tabindex="-1">Suspension <a class="header-anchor" href="#suspension" aria-label="Permalink to &quot;Suspension&quot;">​</a></h3><p>A state where a kingdom or alliance is paused (usually for hitting limits or by an admin decision). A suspended group drops to limited, mostly read‑only access until it&#39;s unsuspended. The exact rules are covered in the subscriptions section.</p><h3 id="premium-feature" tabindex="-1">Premium feature <a class="header-anchor" href="#premium-feature" aria-label="Permalink to &quot;Premium feature&quot;">​</a></h3><p>An extra capability unlocked by a premium plan (or by an accepted grant that includes it) — such as advanced analytics, extra charts, or recommendations. Locked features show an upgrade prompt instead of the feature.</p><hr><h2 id="admin-safety" tabindex="-1">Admin &amp; safety <a class="header-anchor" href="#admin-safety" aria-label="Permalink to &quot;Admin &amp; safety&quot;">​</a></h2><h3 id="audit-log" tabindex="-1">Audit log <a class="header-anchor" href="#audit-log" aria-label="Permalink to &quot;Audit log&quot;">​</a></h3><p>The app&#39;s record of who did what and when. Sensitive details are hidden. Used by senior roles to review changes.</p><h3 id="protection-rule" tabindex="-1">Protection rule <a class="header-anchor" href="#protection-rule" aria-label="Permalink to &quot;Protection rule&quot;">​</a></h3><p>A built‑in guardrail that blocks a dangerous action — like deleting your own account or removing the last Supreme Admin. See <a href="./../roles/protection-rules.html">Safety Rules You&#39;ll Run Into</a>.</p><h3 id="online-indicator" tabindex="-1">Online indicator <a class="header-anchor" href="#online-indicator" aria-label="Permalink to &quot;Online indicator&quot;">​</a></h3><p>A small marker on the Users list showing that a user was active recently (within the last few minutes).</p>',89)])])}const m=a(o,[["render",i]]);export{u as __pageData,m as default};
